generator client {
  provider = "dart run orm"
}

datasource db {
  provider = "postgresql"
  url      = env("DATABASE_URL")
}

model User {
  id                Int        @id @default(autoincrement())
  first_name        String
  last_name         String
  email             String     @unique
  phone             String?    @unique
  password          String
  // auth              Auth       @relation(fields: [id],references: [userId])

  @@map("users")
}

